from __future__ import annotations
import random
class MarkovChain:
    def __init__(self, order: int = 1):
        self.order = order
        self.chain: dict[tuple[str], list[str]] = {}

    def train(self, text: str) -> None:
        for i in range(len(text) - self.order):
            key = tuple(text[i:i + self.order])
            next_char = text[i + self.order]
            if key not in self.chain:
                self.chain[key] = []
            self.chain[key].append(next_char)

    def generate(self, length: int, seed: str | None = None, random_seed: int | None = None) -> str:
        if random_seed is not None:
            random.seed(random_seed)
        if seed is None or len(seed) < self.order:
            key = random.choice(list(self.chain.keys()))
        else:
            key = tuple(seed[-self.order:])
        result = list(key)
        for _ in range(length - self.order):
            next_char = random.choice(self.chain.get(key, ['']))
            result.append(next_char)
            key = tuple(result[-self.order:])
        return ''.join(result)

    def to_dict(self) -> dict:
        return {
            'order': self.order,
            'chain': {str(k): v for k, v in self.chain.items()}
        }

    @classmethod
    def from_dict(cls, data: dict) -> MarkovChain:
        mc = cls(order=data['order'])
        mc.chain = {tuple(k): v for k, v in data['chain'].items()}
        return mc
